def two_sum(nums: List[int], target: int) -> List[int]:
    """返回两个下标，使 nums[i] + nums[j] == target。"""
    seen: dict[int, int] = {}
    for i, v in enumerate(nums):
        diff = target - v
        if diff in seen:
            return [seen[diff], i]
        seen[v] = i
    return []

