from functools import lru_cache

@lru_cache(maxsize=None)
def fib(n: int) -> int:
    """返回第 n 个斐波那契数（F(0)=0, F(1)=1）。"""
    if n < 2:
        return n
    return fib(n - 1) + fib(n - 2)

def fib(n):
    if n < 2:
        return n
    return fib(n - 1) + fib(n - 2)

def fib(n: int) -> int:
    """迭代版斐波那契。"""
    a, b = 0, 1
    for _ in range(n):
        a, b = b, a + b
    return a

def reverse_list(head):
    if head == None:
        return head
    prev = head
    cur = head.next
    while cur:
        prev.next = None
        prev = cur
        cur = cur.next
    return prev

from typing import List

def binary_search(nums: List[int], target: int) -> int:
    """有序数组二分查找 target 的下标，找不到返回 -1。"""
    lo, hi = 0, len(nums) - 1
    while lo <= hi:
        mid = (lo + hi) // 2
        if nums[mid] == target:
            return mid
        elif nums[mid] < target:
            lo = mid + 1
        else:
            hi = mid - 1
    return -1

