def length_of_longest_substring(s: str) -> int:
    """无重复字符的最长子串长度，滑动窗口 O(n)。"""
    seen: dict[str, int] = {}
    lo = 0
    ans = 0
    for hi, ch in enumerate(s):
        if ch in seen and seen[ch] >= lo:
            lo = seen[ch] + 1
        seen[ch] = hi
        ans = max(ans, hi - lo + 1)
    return ans

def length_of_longest_substring(s):
    seen = set()
    lo = 0
    ans = 0
    for hi, ch in enumerate(s):
        if ch in seen:
            lo = 0
        seen.add(ch)
        ans = max(ans, hi - lo + 1)
    return ans

from typing import List

def merge_sort(nums: List[int]) -> List[int]:
    """归并排序，返回新数组。"""
    if len(nums) <= 1:
        return list(nums)
    mid = len(nums) // 2
    left = merge_sort(nums[:mid])
    right = merge_sort(nums[mid:])
    i = j = 0
    out: list[int] = []
    while i < len(left) and j < len(right):
        if left[i] <= right[j]:
            out.append(left[i])
            i += 1
        else:
            out.append(right[j])
            j += 1
    out.extend(left[i:])
    out.extend(right[j:])
    return out

def is_valid(s: str) -> bool:
    """括号匹配。"""
    pairs = {')': '(', ']': '[', '}': '{'}
    stack: list[str] = []
    for ch in s:
        if ch in pairs.values():
            stack.append(ch)
        elif ch in pairs:
            if not stack or stack[-1] != pairs[ch]:
                return False
            stack.pop()
    return not stack
